mapper.select:
SELECT * FROM device_video_profiles WHERE gb_device_id = #{gbDeviceId}
AND (gb_domain = #{gbDomain} OR gb_domain IS NULL OR gb_domain = '')
ORDER BY CASE WHEN gb_domain = #{gbDomain} THEN 0 ELSE 1 END, device_id LIMIT 1

SELECT *
FROM device_video_profiles
WHERE stream_mode = #{streamMode}
  AND source_url LIKE '%' || #{sourcePathSuffix}
ORDER BY device_id
LIMIT 1
